import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
for bp in b['projects']:
    name = bp['path'].split('/')[-2]
    ap = next(p for p in a['projects'] if name in p['path'])
    bpkgs = {p['id']: p['resolvedVersion'] for fw in bp['frameworks'] for p in fw.get('topLevelPackages',[])}
    apkgs = {p['id']: p['resolvedVersion'] for fw in ap['frameworks'] for p in fw.get('topLevelPackages',[])}
    for pkg in sorted(set(list(bpkgs.keys()) + list(apkgs.keys()))):
        bv = bpkgs.get(pkg, '-')
        av = apkgs.get(pkg, '-')
        status = 'Unchanged' if bv == av else f'Changed {bv} -> {av}'
        if bv != av:
            print(f'  {name}/{pkg}: {status}')
print('Done')
